#include <iostream>

template <typename T>
class Storage {
    T val_;
public:
    explicit Storage(T v) : val_{v} {}
    T get() const { return val_; }
};

template <>
class Storage<bool> {
    bool val_;
public:
    explicit Storage(bool v) : val_{v} {}
    bool get() const { return val_; }
    void print() const { std::cout << (val_ ? "true" : "false"); }
};

int countTrue(const Storage<bool> arr[], int n) {
    int count = 0;
    for (int i = 0; i < n; ++i)
        if (arr[i].get()) ++count;
    return count;
}

int main() {
    int n;
    std::cin >> n;
    Storage<bool> arr[6]{ Storage<bool>{false}, Storage<bool>{false},
                          Storage<bool>{false}, Storage<bool>{false},
                          Storage<bool>{false}, Storage<bool>{false} };
    for (int i = 0; i < n; ++i) {
        int v;
        std::cin >> v;
        arr[i] = Storage<bool>{static_cast<bool>(v)};
    }
    std::cout << "True count: " << countTrue(arr, n) << "\n";
    return 0;
}
